impl Solution { pub fn maximum_score_after_operations(edges: Vec<Vec<i32>>, values: Vec<i32>) -> i64 { let mut black_adj = vec![vec![]; values.len()]; for e in edges { black_adj[e[0] as usize].push(e[1] as usize); black_adj[e[1] as usize].push(e[0] as usize); } fn black_dfs(u: usize, p: usize, adj: &Vec<Vec<usize>>, v: &Vec<i32>) -> i64 { let mut sum = 0; for &nb in &adj[u] { if nb != p { sum += black_dfs(nb, u, adj, v); } } if sum == 0 { v[u] as i64 } else { sum.min(v[u] as i64) } } values.iter().map(|&x| x as i64).sum::<i64>() - black_dfs(0, 0, &black_adj, &values) } }